CREATE DATABASE IF NOT EXISTS swiftmart_db;
USE swiftmart_db;

DROP TABLE IF EXISTS warehouses;
CREATE TABLE warehouses (
    warehouse_id INT NOT NULL PRIMARY KEY,
    warehouse_code VARCHAR(20) NOT NULL UNIQUE,
    warehouse_name VARCHAR(100) NOT NULL,
    city VARCHAR(50),
    state VARCHAR(50),
    warehouse_type VARCHAR(20)
);


DROP TABLE IF EXISTS suppliers;
CREATE TABLE suppliers (
    supplier_id INT NOT NULL PRIMARY KEY,
    supplier_code VARCHAR(20) NOT NULL UNIQUE,
    supplier_name VARCHAR(150) NOT NULL,
    city VARCHAR(50),
    phone VARCHAR(20),
    email VARCHAR(150),
    gst_number VARCHAR(25),
    status VARCHAR(20)
);


DROP TABLE IF EXISTS products;
CREATE TABLE products (
    product_id INT NOT NULL PRIMARY KEY,
    sku VARCHAR(25) NOT NULL UNIQUE,
    product_name VARCHAR(150),
    category VARCHAR(80),
    brand VARCHAR(80),
    supplier_id INT,
    unit VARCHAR(30),
    unit_price DECIMAL(10,2),
    status VARCHAR(20)
);


DROP TABLE IF EXISTS inventory;
CREATE TABLE inventory (
    inventory_id INT NOT NULL PRIMARY KEY,
    warehouse_id INT,
    product_id INT,
    batch_number VARCHAR(30),
    quantity INT,
    reorder_level INT,
    unit_cost DECIMAL(10,2),
    last_stocked_date DATE
);


